// Verify nav links
const navLinks = Array.from(document.querySelectorAll('.nav-link'));
const hrefs = navLinks.map(l => l.getAttribute('href'));

// Verify event cards count per section
const colonial = document.querySelectorAll('#periodo-colonial .event-card').length;
const revolucion = document.querySelectorAll('#periodo-revolucion .event-card').length;
const nacional = document.querySelectorAll('#periodo-nacional .event-card').length;

// Verify CSS custom properties loaded
const root = getComputedStyle(document.documentElement);
const hasCSSVars = !!root.getPropertyValue('--color-text').trim();

// Verify stylesheet loaded
const stylesheet = document.querySelector('link[rel="stylesheet"][href="styles.css"]');

JSON.stringify({
  navHrefs: hrefs,
  cardsPerSection: { colonial, revolucion, nacional },
  cssVarsLoaded: hasCSSVars,
  stylesheetPresent: !!stylesheet
});

